spec.expr:
sum (
  celery_queue_length{
    job="$job",
    queue_name=~"$queue_name"
  }
) by (job, queue_name)

sum (
  round(
    increase(
      celery_task_succeeded_total{
        job="$job",
        queue_name=~"$queue_name"
      }[$__range]
    )
  )
) by (job)
/(sum (
  round(
    increase(
      celery_task_succeeded_total{
        job="$job",
        queue_name=~"$queue_name"
      }[$__range]
    )
  )
) by (job)
+sum (
  round(
    increase(
      celery_task_failed_total{
        job="$job",
        queue_name=~"$queue_name"
      }[$__range]
    )
  )
) by (job)
) > -1

sum (
  round(
    increase(
      celery_task_succeeded_total{
        job="$job",
        queue_name=~"$queue_name"
      }[$__range]
    )
  )
) by (job) > 0

sum (
  round(
    increase(
      celery_task_failed_total{
        job="$job",
        queue_name=~"$queue_name"
      }[$__range]
    )
  )
) by (job) > 0

sum (
  round(
    increase(
      celery_task_sent_total{
        job="$job",
        queue_name=~"$queue_name"
