histogram_quantile(0.50,
  sum(
    irate(
      celery_task_runtime_bucket{
        job="$job",
        queue_name=~"$queue_name"
      }[$__rate_interval]
    ) > 0
  ) by (job, le)
)

histogram_quantile(0.95,
  sum(
    irate(
      celery_task_runtime_bucket{
        job="$job",
        queue_name=~"$queue_name"
      }[$__rate_interval]
    ) > 0
  ) by (job, le)
)

histogram_quantile(0.99,
  sum(
    irate(
      celery_task_runtime_bucket{
        job="$job",
        queue_name=~"$queue_name"
      }[$__rate_interval]
    ) > 0
  ) by (job, le)
)

count(
  celery_worker_up{
    job="$job",
  } == 1
)

sum(
  celery_worker_tasks_active{
    job="$job",
  }
)

sum(
  round(
    increase(
      celery_task_received_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    )
  )
)

sum(
  round(
    increase(
      celery_task_succeeded_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    )
  )
)
/(sum(
  round(
    increase(
      celery_task_succeeded_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    )
  )
)
+sum(
  round(
    increase(
      celery_task_failed_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    )
  )
