sum(
  rate(
    celery_task_runtime_sum{
      job="$job",
      queue_name=~"$queue_name"
    }[1w]
  )
)
/
sum(
  rate(
    celery_task_runtime_count{
      job="$job",
      queue_name=~"$queue_name"
    }[1w]
  )
) > 0

round(
  sum (
    increase(
      celery_task_failed_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    ) > 0
  )  by (job, name)
)

round(
  sum (
    increase(
      celery_task_failed_total{
        job="$job",
        queue_name=~"$queue_name"
      }[1w]
    )
  ) by (job, exception) > 0
